/** Item Stats V3 — 구조화된 스펙 인터페이스
 *  v2의 usage 텍스트 필드를 tags/character/resistance/set_bonus/repair/skill_tree/immunities/effects로 분리
 *  wilson_attack = 34, wilson_health = 150, armor_dur_mod = 0.7, armor_abs_mod = 1.0
 */

// ── 구조화 필드 타입 ──

/** 속성 저항 (달/그림자) */
export interface Resistance {
  type: "shadow" | "lunar";
  percent: number;
}

/** 세트 보너스 */
export interface SetBonus {
  /** 세트 식별자: "brightshade" | "voidcloth" | "dreadstone" | "wagpunk" */
  set_id: string;
  /** 세트 효과 설명 */
  effects: { ko: string; en: string };
}

/** 수리 방법 — 렌더 시 itemName(item_id)로 한글명 표시 */
export interface RepairInfo {
  item_id: string;
}

/** 스킬트리 연동 효과 */
export interface SkillTreeEffect {
  ko: string;
  en: string;
}

/** 기타 효과 (구조화되지 않는 설명) */
export interface Effect {
  ko: string;
  en: string;
}

// ── 분류 태그 ──

/** 아이템 분류 태그 */
export type ItemTag =
  | "ranged"      // 원거리 무기/투척
  | "consumable"  // 소모품 (1회용 등)
  | "deployable"  // 설치형
  | "electric"    // 전기 피해
  | "pvp";        // PvP 관련 정보

// ── 메인 인터페이스 ──

export interface ItemStatsV3 {
  // ── 수치 필드 (v2 동일) ──
  damage?: number;
  uses?: number;
  armor_hp?: number;
  absorption?: number;
  speed_mult?: number;
  dapperness?: number;
  insulation?: number;
  summer_insulation?: number;
  waterproof?: number;
  fuel_time?: number;
  perish_time?: number;
  planar_damage?: number;
  shadow_bonus?: number;
  planar_def?: number;
  health_regen?: number;
  hunger_drain?: number;
  slots?: number;

  // ── 구조화 필드 (usage 대체) ──
  /** 분류 태그 */
  tags?: ItemTag[];
  /** 캐릭터 전용 (prefab name: "wathgrithr", "wormwood" 등) */
  character?: string;
  /** 속성 저항 */
  resistance?: Resistance[];
  /** 그림자/달 레벨 */
  shadow_level?: number;
  /** 세트 보너스 */
  set_bonus?: SetBonus;
  /** 수리 방법 */
  repair?: RepairInfo;
  /** 스킬트리 연동 효과 */
  skill_tree?: SkillTreeEffect[];
  /** 면역 (fire, electric, shadow_aura 등) */
  immunities?: string[];
  /** 기타 효과 */
  effects?: Effect[];
}

